3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const liveSet = new Set<string>();
5	  for (const [x, y] of cells) {
6	    liveSet.add(key(x, y));
7	  }
8	
9	  const neighborCounts = new Map<string, number>();
10	
11	  for (const [x, y] of cells) {
12	    for (let dx = -1; dx <= 1; dx++) {
13	      for (let dy = -1; dy <= 1; dy++) {
14	        if (dx === 0 && dy === 0) continue;
15	        const nx = x + dx;
16	        const ny = y + dy;
17	        const k = key(nx, ny);
18	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
19	      }
20	    }
21	  }
22	
23	  const result: Cell[] = [];
24	  for (const [k, count] of neighborCounts) {
25	    const isAlive = liveSet.has(k);
26	    if (isAlive && (count === 2 || count === 3)) {
27	      result.push(parseKey(k));
28	    } else if (!isAlive && count === 3) {
29	      result.push(parseKey(k));
30	    }
31	  }
32	
33	  // Also include live cells with 0 neighbors? They would die anyway (underpopulation).
34	  // No need - cells with 0 neighbors have count undefined in neighborCounts but
35	  // they are alive with 0 neighbors so they die per rule 1.
36	
37	  return result;
38	}
